+
+    #[test]
+    fn test_message_with_vec() {
+        let msg = Message::new(vec![1, 2, 3]);
+        assert!(msg.is::<Vec<i32>>());
+        assert_eq!(msg.downcast::<Vec<i32>>().unwrap(), vec![1, 2, 3]);
