+
+    #[test]
+    fn test_message_with_tuple() {
+        let msg = Message::new((1i32, "hello", 3.14f64));
+        assert!(msg.is::<(i32, &str, f64)>());
+
+        let (a, b, c) = msg.downcast::<(i32, &str, f64)>().unwrap();
+        assert_eq!(a, 1);
+        assert_eq!(b, "hello");
+        assert!((c - 3.14).abs() < f64::EPSILON);
+    }
